"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";
import Image from "next/image";
import { Plus } from "lucide-react";
import { Badge } from "@/components/ui/Badge";
import { Button } from "@/components/ui/Button";
import { LandingFabActionSheet } from "@/components/dashboard/LandingFabActionSheet";
import { getLandingFabConfig } from "@stockright/shared/demo";
import { DEMO_PROFILE_USER } from "@stockright/shared/demo";

interface TopBarProps {
  warehouseName?: string;
}

export function TopBar({ warehouseName }: TopBarProps) {
  const pathname = usePathname() ?? "";
  const fabConfig = getLandingFabConfig(pathname);
  const [sheetOpen, setSheetOpen] = useState(false);

  return (
    <header
      className="flex items-center justify-between border-b border-[var(--border-default)] bg-[var(--bg-surface)] px-4"
      style={{ height: "var(--topbar-height)" }}
    >
      <div className="flex items-center gap-2">
        <Image src="/wordmark.svg" alt="StockRight" width={120} height={24} priority />
        {warehouseName && (
          <span className="hidden font-mono text-[11px] uppercase tracking-widest text-[var(--text-tertiary)] sm:inline">
            {warehouseName}
          </span>
        )}
      </div>

      <div className="flex items-center gap-3">
        <Badge variant="online" className="hidden sm:inline-flex">
          ● Online
        </Badge>

        {fabConfig && (
          <Button
            type="button"
            size="sm"
            variant="primary"
            className="hidden sm:inline-flex"
            onClick={() => setSheetOpen(true)}
          >
            <Plus size={14} />
            Add
          </Button>
        )}

        <Link
          href="/settings"
          className="hidden size-9 shrink-0 items-center justify-center rounded-full border border-[var(--border-default)] bg-[var(--brand-subtle)] font-[family-name:var(--font-display)] text-[14px] font-semibold text-[var(--brand-text)] transition-opacity hover:opacity-90 focus-visible:outline-none focus-visible:ring-[3px] focus-visible:ring-[var(--focus-ring)] sm:flex"
          aria-label="Profile and settings"
        >
          {DEMO_PROFILE_USER.initials}
        </Link>

        {fabConfig && (
          <LandingFabActionSheet
            open={sheetOpen}
            title={fabConfig.title}
            actions={fabConfig.actions}
            onClose={() => setSheetOpen(false)}
          />
        )}
      </div>
    </header>
  );
}
