"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { LayoutDashboard, Package, Users, Banknote, UserCircle } from "lucide-react";
import { cn } from "@/lib/utils";

const navGroups = [
  {
    label: "Operations",
    items: [
      { href: "/", label: "Home", icon: LayoutDashboard },
      { href: "/stock", label: "Stock", icon: Package },
      { href: "/parties", label: "Parties", icon: Users },
      { href: "/money", label: "Money", icon: Banknote },
    ],
  },
  {
    label: "Account",
    items: [{ href: "/settings", label: "Profile & settings", icon: UserCircle }],
  },
];

export function SideNav() {
  const pathname = usePathname() ?? "";

  return (
    <nav
      className="flex flex-col overflow-y-auto border-r border-[var(--border-default)] bg-[var(--bg-subtle)]"
      style={{ width: "var(--sidenav-width)" }}
    >
      <div className="flex-1 space-y-6 py-4">
        {navGroups.map((group) => (
          <div key={group.label}>
            <p className="mb-2 px-4 font-mono text-[9px] uppercase tracking-[0.1em] text-[var(--text-tertiary)]">
              {group.label}
            </p>
            {group.items.map(({ href, label, icon: Icon }) => {
              const base = pathname.replace(/\/$/, "") || "/";
              const hrefNorm = href.replace(/\/$/, "") || "/";
              const isActive =
                hrefNorm === "/"
                  ? base === "/"
                  : base === hrefNorm || base.startsWith(`${hrefNorm}/`);
              return (
                <Link
                  key={href}
                  href={href}
                  className={cn(
                    "mx-2 flex items-center gap-3 rounded-[var(--radius-md)] px-3 py-2 text-[14px] font-medium transition-colors duration-[var(--duration-fast)]",
                    isActive
                      ? "bg-[var(--brand-ui)] text-[var(--text-on-brand)]"
                      : "text-[var(--text-secondary)] hover:bg-[var(--bg-inset)] hover:text-[var(--text-primary)]"
                  )}
                >
                  <Icon size={16} />
                  {label}
                </Link>
              );
            })}
          </div>
        ))}
      </div>
    </nav>
  );
}
